component.schema:
{
 "description": "IdentityOIDCClient is the Schema for the identityoidcclients API",
 "properties": {
  "spec": {
   "description": "IdentityOIDCClientSpec defines the desired state of IdentityOIDCClient",
   "properties": {
    "accessTokenTTL": {
     "default": "24h",
     "description": "AccessTokenTTL is the time-to-live for access tokens obtained by the client.\nAccepts duration format strings.",
     "type": "string"
    },
    "assignments": {
     "description": "Assignments is a list of assignment resources associated with the client.\nClient assignments limit the Vault entities and groups that are allowed to authenticate through the client.\nBy default, no Vault entities are allowed. To allow all Vault entities to authenticate through the client,\nsupply the built-in allow_all assignment.",
     "items": {
      "type": "string"
     },
     "type": "array",
     "x-kubernetes-list-type": "set"
    },
    "authentication": {
     "description": "Authentication is the kube auth configuration to be used to execute this request",
     "properties": {
      "namespace": {
       "description": "Namespace is the Vault namespace to be used in all the operations withing this connection/authentication. Only available in Vault Enterprise.",
       "type": "string"
      },
      "path": {
       "default": "kubernetes",
       "description": "Path is the path of the role used for this kube auth authentication. The operator will try to authenticate at {[namespace/]}auth/{spec.path}",
       "pattern": "^(?:/?[\\w;:@\u0026=\\$-\\.\\+]*)+/?",
       "type": "string"
      },
      "role": {
       "description": "Role the role to be used during authentication",
       "type": "string"
      },
      "serviceAccount": {
       "default": {
        "name": "default"
       },
       "description": "ServiceAccount is the service account used for the kube auth authentication",
       "properties": {
        "name": {
         "description": "Name of the referent.\nMore info: https://kubernetes.io/docs/concepts/overview/working-with-objects/names/#names\nTODO: Add other useful fields. apiVersion, kind, uid?",
         "type": "string"
        }
       },
       "type": "object",
       "x-kubernetes-map-type": "atomic"
      }
     },
     "type": "object"
    },
    "clientType": {
     "default": "confidential",
     "description": "ClientType is the client type based on its ability to maintain confidentiality of credentials.\nThis cannot be modified after creation. Must be \"confidential\" or \"public\".",
     "enum": [
      "confidential",
      "public"
     ],
     "type": "string"
    },
    "connection": {
     "description": "Connection represents the information needed to connect to Vault. This operator uses the standard Vault environment variables to connect to Vault. If you need to override those settings and for example connect to a different Vault instance, you can do with this section of the CR.",
     "properties": {
      "address": {
       "description": "Address Address of the Vault server expressed as a URL and port, for example: https://127.0.0.1:8200/",
       "type": "string"
      },
      "maxRetries": {
       "description": "MaxRetries Maximum number of retries when certain error codes are encountered. The default is 2, for three total attempts. Set this to 0 or less to disable retrying. Error codes that are retried are 412 (client consistency requirement not satisfied) and all 5xx except for 501 (not implemented).",
       "type": "integer"
      },
      "tLSConfig": {
       "properties": {
        "cacert": {
         "description": "Cacert Path to a PEM-encoded CA certificate file on the local disk. This file is used to verify the Vault server's SSL certificate. This environment variable takes precedence over a cert passed via the secret.",
         "type": "string"
        },
        "skipVerify": {
         "description": "SkipVerify Do not verify Vault's presented certificate before communicating with it. Setting this variable is not recommended and voids Vault's security model.",
         "type": "boolean"
        },
        "tlsSecret": {
         "description": "TLSSecret namespace-local secret containing the tls material for the connection. the expected keys for the secret are: ca bundle -\u003e \"ca.crt\", certificate -\u003e \"tls.crt\", key -\u003e \"tls.key\"",
         "properties": {
          "name": {
           "description": "Name of the referent.\nMore info: https://kubernetes.io/docs/concepts/overview/working-with-objects/names/#names\nTODO: Add other useful fields. apiVersion, kind, uid?",
           "type": "string"
          }
         },
         "type": "object",
         "x-kubernetes-map-type": "atomic"
        },
        "tlsServerName": {
         "description": "TLSServerName Name to use as the SNI host when connecting via TLS.",
         "type": "string"
        }
       },
       "type": "object"
      },
      "timeOut": {
       "description": "Timeout Timeout variable. The default value is 60s.",
       "type": "string"
      }
     },
     "type": "object"
    },
    "idTokenTTL": {
     "default": "24h",
     "description": "IDTokenTTL is the time-to-live for ID tokens obtained by the client.\nAccepts duration format strings. The value should be less than the verification_ttl on the key.",
     "type": "string"
    },
    "key": {
     "default": "default",
     "description": "Key is a reference to a named key resource. This key will be used to sign ID tokens for the client.\nThis cannot be modified after creation. If not supplied, defaults to the built-in default key.",
     "type": "string"
    },
    "name": {
     "description": "The name of the obejct created in Vault. If this is specified it takes precedence over {metatada.name}",
     "pattern": "[a-z0-9]([-a-z0-9]*[a-z0-9])?",
     "type": "string"
    },
    "redirectURIs": {
     "description": "RedirectURIs is the list of redirection URI values used by the client.\nOne of these values must exactly match the redirect_uri parameter value used in each authentication request.",
     "items": {
      "type": "string"
     },
     "type": "array",
     "x-kubernetes-list-type": "set"
    }
   },
   "type": "object"
  }
 },
 "title": "Identity OIDC Client",
 "type": "object"
}
